/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;
    const adj = Array(n).fill(0).map(() => []);

    // Build adjacency list
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate through all non-empty subsets of nodes (represented by a bitmask from 1 to 2^n - 1)
    for (let mask = 1; mask < (1 << n); mask++) {
        // 1. Check the sum of node values (Parity check)
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        // If the sum is odd, this subset does not satisfy the second condition, so skip.
        if (sum % 2 !== 0) {
            continue;
        }

        // 2. Check if the induced subgraph is connected

        // Find the nodes present in the subset 'mask'
        const subsetNodes = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetNodes.push(i);
            }
        }

        if (subsetNodes.length === 0) {
            // Should not happen due to mask starting from 1
            continue;
        }

        // Use BFS or DFS starting from the first node in the subset to check connectivity
        const startNode = subsetNodes[0];

        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            visitedCount++;

            for (const v of adj[u]) {
                // Check if v is in the subset AND has not been visited
                if (((mask >> v) & 1) && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // The subgraph is connected if and only if the number of visited nodes
        // within the induced subgraph equals the total number of nodes in the subset.
        if (visitedCount === subsetNodes.length) {
            count++;
        }
    }

    return count;
}

